class Solution {
    public int numberOfWays(int n, int x, int y) {
        long mod = 1000000007;
        long ways = 1;
        for (int i = 0; i < n; i++) {
            ways = (ways * x) % mod;
        }
        for (int i = 0; i < y; i++) {
            ways = (ways * y) % mod;
        }
        return (int) ways;
    }
}
